boolean transfer(Account from, Account to, int amount) throws InterruptedException {
    if (!from.lock.tryLock(200, java.util.concurrent.TimeUnit.MILLISECONDS)) {
        return false;
    }
    try {
        if (!to.lock.tryLock(200, java.util.concurrent.TimeUnit.MILLISECONDS)) {
            return false;
        }
        try {
            if (from.balance < amount) {
                return false;
            }
            from.balance -= amount;
            to.balance += amount;
            return true;
        } finally {
            to.lock.unlock();
        }
    } finally {
        from.lock.unlock();
    }
}

